package org.apache.commons.jxpath.ri.model.dom;

import io.cucumber.junit.Cucumber;
import io.cucumber.junit.CucumberOptions;
import org.junit.runner.RunWith;

@RunWith(Cucumber.class)
@CucumberOptions(
    features = "src/test/resources",
    glue = "org.apache.commons.jxpath.ri.model.dom.steps",
    plugin = {"pretty"}
)
public class CucumberTest {
}

package org.apache.commons.jxpath.ri.model.dom.steps;

import io.cucumber.java.en.Given;
import io.cucumber.java.en.When;
import io.cucumber.java.en.Then;
import org.w3c.dom.Document;
import org.w3c.dom.Element;
import org.w3c.dom.NodeList;
import org.apache.commons.jxpath.JXPathContext;
import org.apache.commons.jxpath.Pointer;
import static org.junit.Assert.*;

import javax.xml.parsers.DocumentBuilder;
import javax.xml.parsers.DocumentBuilderFactory;
import java.io.ByteArrayInputStream;
import java.nio.charset.StandardCharsets;

public class StepDefs {

    private Document document;
    private String xPathResult;
    private JXPathContext context;

    @Given("an XML document containing:")
    public void an_xml_document_containing(String xmlContent) throws Exception {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);
            DocumentBuilder builder = factory.newDocumentBuilder();

            // Parse the XML content
            ByteArrayInputStream inputStream = new ByteArrayInputStream(xmlContent.getBytes(StandardCharsets.UTF_8));
            this.document = builder.parse(inputStream);

            // Create JXPath context for the document
            this.context = JXPathContext.newContext(document);
        } catch (Exception e) {
            throw new RuntimeException("Failed to parse XML document", e);
        }
    }

    @Given("I have registered the prefix {string} for the namespace URI {string}")
    public void i_have_registered_the_prefix_for_the_namespace_uri(String prefix, String namespaceUri) {
        // Register the namespace in the JXPath context
        context.registerNamespace(prefix, namespaceUri);
    }

    @When("I retrieve the XPath for the second child element {string}")
    public void i_retrieve_the_xpath_for_the_second_child_element(String elementName) {
        try {
            // Find the second child element (the b:elem element)
            NodeList childNodes = document.getDocumentElement().getChildNodes();
            Element targetElement = null;

            int count = 0;
            for (int i = 0; i < childNodes.getLength(); i++) {
                if (childNodes.item(i).getNodeType() == org.w3c.dom.Node.ELEMENT_NODE) {
                    count++;
                    if (count == 2) {
                        targetElement = (Element) childNodes.item(i);
                        break;
                    }
                }
            }

            if (targetElement != null) {
                // Create a pointer for this element and get its path
                Pointer pointer = context.getPointer(targetElement);
                if (pointer != null) {
                    this.xPathResult = pointer.asPath();
                } else {
                    this.xPathResult = "NULL_POINTER";
                }
            } else {
                this.xPathResult = "ELEMENT_NOT_FOUND";
            }
        } catch (Exception e) {
            this.xPathResult = "ERROR: " + e.getMessage();
        }
    }

    @Then("the generated XPath should be {string}")
    public void the_generated_xpath_should_be(String expectedXPath) {
        assertEquals("Generated XPath does not match expected value", expectedXPath, xPathResult);
    }

    @Then("the position index should be calculated based on the local name and namespace URI, not the literal node name \\(prefix:local\\)")
    public void the_position_index_should_be_calculated_based_on_local_name_and_namespace_uri() {
        // Verify that the XPath calculation considers namespace URI and local name
        // rather than just literal prefixes
        System.out.println("Actual XPath: " + xPathResult);

        // The expected behavior is that even though the second element has a different prefix (b:elem),
        // it should still be indexed as [2] based on its position among elements with the same local name
        // and namespace URI as the first element (which is a:elem).
        // If the bug exists, it might generate something different than expected.
    }
}

