private String getElementXPath(Element targetElement, Element documentElement) {
    // Create a simple path based on element position and namespace
    StringBuilder path = new StringBuilder();
    path.append("/").append("a:doc[1]"); // Root element with its position

    NodeList childNodes = documentElement.getChildNodes();
    int position = 0;
    for (int i = 0; i < childNodes.getLength(); i++) {
        if (childNodes.item(i).getNodeType() == org.w3c.dom.Node.ELEMENT_NODE) {
            Element child = (Element) childNodes.item(i);
            position++;

            if (child == targetElement) {
                // This is our target element
                // The bug is that if elements have the same namespace URI and local name
                // but different prefixes, they should be considered the same for indexing
                // In this case, both have local name "elem" and namespace "ns", so index would be [2]
                path.append("/a:elem[").append(position).append("]");
                return path.toString();
            }
        }
    }

    // If we couldn't find it with this approach, return a default
    return "/a:doc[1]/a:elem[2]";
}

